        jQuery(function ($) {

        $('.toggle-button').on('click', function (e) {
        e.preventDefault();

        var targetSelector = this.getAttribute('data-target');
        var $target = $(targetSelector);
        var $btn = $(this);
        var isMobile = window.matchMedia('(max-width: 800px)').matches;
        var isVisible = $target.is(':visible');

        $('.togglable').stop(true, true);

        $('.togglable').not(targetSelector).hide('slow');

        $('.toggle-button').removeClass('mobile-sticky');

        if (isVisible) {
        $target.hide('slow');
        return;
        }

        $target.show('slow', function () {

        if (isMobile) {
        $btn.addClass('mobile-sticky');

        $('html, body').animate({
        scrollTop: $btn.offset().top
        }, 250);
        }

        });
        });

        });

        jQuery(function() {

        jQuery('.titre').each(function() {
        var m =jQuery(this).find(".master").attr("id");
        if(getValue(''+m+'.value')>0)
        {
        jQuery( this.getAttribute( 'ch-target' ) ).show();
        }
        else{
        if(getValue(''+m+'.value') == null){
        jQuery( this.getAttribute( 'ch-target' ) ).hide();
        }
        }
        if(getValue(''+m+'.value') == ''){
        jQuery( this.getAttribute( 'ch-target' ) ).hide();
        }
        });

        jQuery( '.titre' ).on( 'change', function() {

        var m =jQuery(this).find(".master").attr("id");
        if(getValue(''+m+'.value')>0 || getValue(''+m+'.value') != null)
        {
        jQuery( this.getAttribute( 'ch-target' ) ).show();
        }
        else{
        if(getValue(''+m+'.value') == null){
        jQuery( this.getAttribute( 'ch-target' ) ).hide();
        }

        }
        if(getValue(''+m+'.value') == ''){
        jQuery( this.getAttribute( 'ch-target' ) ).hide();
        }


        });

        });


        

        jQuery(function() {
        if (getValue('locationTypeValue.value') == '') {
        setValue('locationTypeValue.value','Le site même');
        }if (getValue('locationTypeValue.value') == '') {
        setValue('locationTypeValue.value','Le site même');
        }if ((getValue('locationTypeValue.value') == 'Point fixe ou satellite') || (getValue('locationTypeValue.value') == 'Clinique privée') || (getValue('locationTypeValue.value') == 'Maison privée') || (getValue('locationTypeValue.value') == 'Télémédecine')) {
        jQuery('#locationValue').hide()
        }

        //jQuery('#locationType:not(:has(.required))').append('*');
        jQuery('#locationTypeValue').on( 'change', function() {
        if (getValue('locationTypeValue.value') == 'Le site même') {
        jQuery('#locationValue').show();
        //jQuery('#locationValue:not(:has(.required))').append('*');
        } else if (getValue('locationTypeValue.value') == 'Site autre que celui du patient') {
        jQuery('#locationValue').show();
        //jQuery('#locationValue:not(:has(.required))').append('*');
        } else {
        jQuery('#locationValue').hide()
        }
        });
        });

        var maxMembers = 10;
        var visibleRows = [];

        // Attendre que tout soit chargé (y compris les scripts OpenMRS)
        jQuery(document).ready(function() {
        // Petit délai pour laisser OpenMRS pré-remplir les champs
        setTimeout(function() {
        initFamilySection();
        }, 500);
        });

        // Alternative: aussi écouter window.load
        jQuery(window).on('load', function() {
        setTimeout(function() {
        initFamilySection();
        }, 300);
        });

        function initFamilySection() {
        jQuery('.family-row').each(function() {
        var row = jQuery(this);
        var rowNum = parseInt(row.attr('data-row'));
        var hasData = false;

        // Vérifier les inputs text
        row.find('input[type="text"]').each(function() {
        var val = jQuery(this).val();
        if (val && val.trim() !== '') {
        hasData = true;
        return false; // Break la boucle
        }
        });

        // Vérifier les selects
        if (!hasData) {
        row.find('select').each(function() {
        var val = jQuery(this).val();
        if (val && val !== '') {
        hasData = true;
        return false; // Break la boucle
        }
        });
        }

        // Vérifier aussi les inputs hidden (OpenMRS stocke parfois les valeurs là)
        if (!hasData) {
        row.find('input[type="hidden"]').each(function() {
        var val = jQuery(this).val();
        var name = jQuery(this).attr('name');
        // Ignorer les hidden qui commencent par underscore (champs de contrôle)
        if (val && val.trim() !== '' && name && !name.startsWith('_')) {
        hasData = true;
        return false;
        }
        });
        }

        // Vérifier les checkboxes cochées
        if (!hasData) {
        row.find('input[type="checkbox"]:checked').each(function() {
        hasData = true;
        return false;
        });
        }

        if (hasData) {
        showRow(rowNum);
        }
        });

        updateCounter();
        }

        function addFamilyMember() {
        var added = false;
        var i;

        for (i = 1; i <= maxMembers; i++) {
        if (visibleRows.indexOf(i) === -1) {
        showRow(i);
        added = true;
        break;
        }
        }

        if (!added) {
        alert('Maximum de ' + maxMembers + ' membres atteint');
        }

        updateCounter();
        }

        function showRow(rowNum) {
        var row = jQuery('.family-row[data-row="' + rowNum + '"]');
        row.addClass('visible');

        if (visibleRows.indexOf(rowNum) === -1) {
        visibleRows.push(rowNum);
        visibleRows.sort(function(a, b) { return a - b; });
        }
        }

        function removeFamilyMember(rowNum) {
        var row = jQuery('.family-row[data-row="' + rowNum + '"]');

        // Vider les champs
        row.find('input[type="text"]').val('');
        row.find('select').prop('selectedIndex', 0);
        row.find('input[type="hidden"]').not('[name^="_"]').val('');

        // Cacher la ligne
        row.removeClass('visible');

        // Retirer du tableau
        var index = visibleRows.indexOf(rowNum);
        if (index > -1) {
        visibleRows.splice(index, 1);
        }

        updateCounter();
        }

        function updateCounter() {
        var count = visibleRows.length;
        jQuery('#memberCounter').text('(' + count + '/' + maxMembers + ' membres)');

        if (count >= maxMembers) {
        jQuery('#btnAddMember').prop('disabled', true);
        } else {
        jQuery('#btnAddMember').prop('disabled', false);
        }
        }

        jQuery(document).ready(function() {
        // Accordéon toggle
        jQuery('#section-eval-psy .accordion-header').on('click', function() {
        var header = jQuery(this);
        var content = header.next('.accordion-content');

        header.toggleClass('active');
        content.toggleClass('active');
        });
        });
